// src/util/spinner.ts
var FRAMES = ['\u25D2', '\u25D0', '\u25D3', '\u25D1'];
var INTERVAL = 80;
function formatElapsed(ms) {
  const s = Math.floor(ms / 1000);
  const m2 = Math.floor(s / 60);
  return m2 > 0 ? `${m2}m ${String(s % 60).padStart(2, '0')}s` : `${s}s`;
}
var isTTY2 = process.stdout.isTTY;
var c2 = {
  reset: isTTY2 ? '\x1B[0m' : '',
  green: isTTY2 ? '\x1B[32m' : '',
  red: isTTY2 ? '\x1B[31m' : '',
  dim: isTTY2 ? '\x1B[2m' : '',
  clearLine: isTTY2 ? '\x1B[2K' : '',
  cursorUp: n => (isTTY2 ? `\x1B[${n}A` : ''),
};

class MultiSpinner {
  tasks = [];
  frameIdx = 0;
  timer = null;
  rendered = false;
  maxMsgLen = 0;
  add(id, msg) {
    this.tasks.push({ id, msg, state: 'spinning', startedAt: Date.now(), finishedAt: null });
    if (msg.length > this.maxMsgLen) this.maxMsgLen = msg.length;
    if (isTTY2 && !this.timer) {
      this.startTimer();
    }
    this.render();
  }
  done(id) {
    const task = this.tasks.find(t => t.id === id);
    if (task) {
      task.state = 'done';
      task.finishedAt = Date.now();
    }
    this.render();
    this.checkAllDone();
  }
  fail(id) {
    const task = this.tasks.find(t => t.id === id);
    if (task) {
      task.state = 'failed';
      task.finishedAt = Date.now();
    }
    this.render();
    this.checkAllDone();
  }
  stop() {
    if (this.timer) {
      clearInterval(this.timer);
      this.timer = null;
    }
    this.render();
  }
  startTimer() {
    this.timer = setInterval(() => {
      this.frameIdx = (this.frameIdx + 1) % FRAMES.length;
      this.render();
    }, INTERVAL);
  }
  checkAllDone() {
    if (this.tasks.every(t => t.state !== 'spinning')) {
      this.stop();
    }
  }
  render() {
    if (!isTTY2) return;
    if (this.rendered) {
      process.stdout.write(c2.cursorUp(this.tasks.length));
    }
    const cols = process.stdout.columns || 80;
    const now = Date.now();
    const frame = FRAMES[this.frameIdx];
    for (const task of this.tasks) {
      let prefix;
      switch (task.state) {
        case 'done':
          prefix = `${c2.green}\u2713${c2.reset}`;
          break;
        case 'failed':
          prefix = `${c2.red}\u2717${c2.reset}`;
          break;
        default:
          prefix = `${c2.dim}${frame}${c2.reset}`;
      }
      const elapsed = (task.finishedAt ?? now) - task.startedAt;
      const timeStr = formatElapsed(elapsed).padStart(8);
      const maxMsg = cols - 13;
      let msg = task.msg;
      if (maxMsg > 4 && msg.length > maxMsg) {
        msg = msg.slice(0, maxMsg - 1) + '\u2026';
      }
      const padded = msg.padEnd(Math.min(this.maxMsgLen, maxMsg > 0 ? maxMsg : this.maxMsgLen));
      const time = `${c2.dim}${timeStr}${c2.reset}`;
      process.stdout.write(`${c2.clearLine}\r${prefix}  ${padded}  ${time}
`);
    }
    this.rendered = true;
  }
}

// src/core/review-runner.ts
async function runReviewers(reviewers, vars, config, sessionId) {
  const entries = Object.entries(reviewers);
  if (entries.length === 0) return 'No reviewers configured.';
  const ms = new MultiSpinner();
  for (const [name, reviewer] of entries) {
    ms.add(name, `Reviewing: ${reviewer.desc}`);
  }
  const results = await Promise.allSettled(
    entries.map(async ([name, reviewer]) => {
      if (sessionId) {
        appendEvent(sessionId, {
          ts: new Date().toISOString(),
          event: 'subtask:started',
          metadata: { task: name, parent: 'review' },
        });
      }
      const prompt = resolvePromptVars(reviewer.prompt, vars);
      const binary = resolveBinary(reviewer.binaries, config);
      debugLog(`[review] running reviewer "${name}" with binary "${binary}"`);
      try {
        const output = await spawnPrintRaw(binary, prompt, {
          cwd: vars.worktree,
          timeout: resolveTimeout(reviewer.timeout, config),
          sessionId,
          label: `review-${name}`,
        });
        ms.done(name);
        if (sessionId) {
          appendEvent(sessionId, {
            ts: new Date().toISOString(),
            event: 'subtask:completed',
            metadata: { task: name, parent: 'review' },
          });
        }
        return { reviewer: name, issues: output };
      } catch (err) {
        ms.fail(name);
        if (sessionId) {
          appendEvent(sessionId, {
            ts: new Date().toISOString(),
            event: 'subtask:failed',
            metadata: { task: name, parent: 'review', error: String(err) },
          });
        }
        throw err;
      }
    }),
  );
  ms.stop();
  const collected = [];
  for (const result of results) {
    if (result.status === 'fulfilled' && result.value.issues.trim()) {
      collected.push(result.value);
    } else if (result.status === 'rejected') {
      debugLog(`[review] reviewer failed: ${result.reason}`);
    }
  }
  if (collected.length === 0) return 'No issues found.';
  const summaryInput = collected.map(
    r2 => `## ${r2.reviewer}
${r2.issues}`,
  ).join(`

---

`);
  const summaryPrompt = `You are a review summarizer. Below are the outputs from multiple independent reviewers analyzing the same document.

Your job:
1. Merge all findings into ONE concise, deduplicated problem list
2. Remove duplicate or overlapping issues
3. Number each unique problem
4. Be concise \u2014 one line per problem, no preamble

Reviewer outputs:

${summaryInput}

Output ONLY the numbered problem list. If no real issues, output "No issues found."`;
  const summaryBinary = resolveBinary(undefined, config);
  try {
    const summary = await spawnPrintRaw(summaryBinary, summaryPrompt, {
      cwd: vars.worktree,
      spinnerMsg: 'Summarizing review findings',
      sessionId,
      label: 'review-summarize',
    });
    return summary;
  } catch (err) {
    debugLog(`[review] summarization failed: ${err}`);
    return collected.map(
      r2 => `[${r2.reviewer}]
${r2.issues}`,
    ).join(`

`);
  }
}

// src/cli/spec-review.ts
init_format();
function createSpecReviewCommand() {
  return new Command('spec-review')
    .description('Run spec reviewers for the current session (stateless, stdout only)')
    .action(async () => {
      try {
        await runSpecReview();
      } catch (err) {
        logError(err instanceof Error ? err.message : String(err));
        process.exit(1);
      }
    });
}
async function runSpecReview() {
  const repoPath = getGitRoot();
  const worktree = getWorktree();
  const session = getSessionByWorktree(repoPath, worktree);
  if (!session) {
    logError('No session found in this worktree.');
    process.exit(1);
  }
  const config = readConfig(session.id);
  if (!config) {
    logError('No config found for this session.');
    process.exit(1);
  }
  const status = ensureStatus(session.id);
  const version = status.version || 1;
  const typeJsonPath = join20(sessionDir(session.id), 'artifacts', `v${version}`, 'type.json');
  if (!existsSync32(typeJsonPath)) {
    logError(`No type.json found at ${typeJsonPath}. Has route_type completed?`);
    process.exit(1);
  }
  const typeInfo = JSON.parse(readFileSync27(typeJsonPath, 'utf-8'));
  const typeName = typeInfo.type;
  const typeConfig = config.types[typeName];
  if (!typeConfig) {
    logError(`Type "${typeName}" not found in config.`);
    process.exit(1);
  }
  const reviewers = typeConfig.spec_reviewers;
  if (!reviewers || Object.keys(reviewers).length === 0) {
    console.log('No spec reviewers configured for this type.');
    return;
  }
  const vars = buildPromptVars(worktree, version);
  const summary = await runReviewers(reviewers, vars, config, session.id);
  console.log(summary);
}

